type OnCommentCreateProxy struct {
	automation.UnimplementedOnCommentCreateServer
	client automation.OnCommentCreateClient
}

func init() {
	proxyutil.Register(&automation.OnCommentCreate_ServiceDesc, NewOnCommentCreateProxy)
}
func NewOnCommentCreateProxy(cc grpc.ClientConnInterface) automation.OnCommentCreateServer {
	return &OnCommentCreateProxy{client: automation.NewOnCommentCreateClient(cc)}
}
